SELECT COUNT(*) AS active_projects_count
FROM conservation_projects
WHERE status = 'Active';

SELECT COUNT(*) AS record_count
FROM historical_records
WHERE species_id = 0;

SELECT COUNT(*) AS critically_endangered_species_count
FROM species
WHERE conservation_status = (SELECT status_id FROM conservation_status WHERE status_name = 'CR');

SELECT project_name
FROM conservation_projects
WHERE status = 'Active';
